// Build the Claude API request body from upstream data.
// References:
//   - Set Period & Topic    -> period_start, period_end, ntfy_topic
//   - Query Aggregates      -> sessions_active, sessions_new, bytes_in, bytes_out,
//                              events_total, events_high, events_medium,
//                              events_critical, anomalies_open, top_source_ips,
//                              top_event_types

const period   = $('Set Period & Topic').first().json;
const metrics  = $('Query Aggregates').first().json;

const payload = {
  period_start:    period.period_start,
  period_end:      period.period_end,
  sessions_active: metrics.sessions_active,
  sessions_new:    metrics.sessions_new,
  bytes_in:        Number(metrics.bytes_in),
  bytes_out:       Number(metrics.bytes_out),
  events_total:    metrics.events_total,
  events_high:     metrics.events_high,
  events_medium:   metrics.events_medium,
  events_critical: metrics.events_critical,
  anomalies_open:  metrics.anomalies_open,
  top_source_ips:  metrics.top_source_ips || [],
  top_event_types: metrics.top_event_types || []
};

const systemPrompt = `You are the AI ops analyst for EventHorizon VPN, a self-hosted privacy VPN running on a Vultr LA hub. Your job: review the network metadata pulse every 2 hours and flag anything that genuinely needs operator attention. The operator is solo, hands-on, and you are NOT his only line of defense — fail2ban, UFW, Suricata, and CrowdSec already react in real time. Your job is the 2h trend layer, not paging on every blocked scanner.

The operator is the SOLE user of this VPN — no customers. Logging exists for self-validation. Threat model: "is the operator's own infrastructure leaking or under unusual attack?"

Fields per pulse:
- sessions_active / sessions_new: WireGuard peer connection counts in the period
- bytes_in / bytes_out: aggregate traffic over WG tunnels
- events_total / events_high / events_medium / events_critical: counts by severity
- top_source_ips: top 5 attacker IPs with counts
- top_event_types: top 5 event types with counts
- anomalies_open: count of unresolved anomalies

KNOWN BASELINE for THIS operator's hub (do NOT flag these as anomalies — they are the steady state):
- sessions: 1-5 distinct active users per 2h cycle is normal. The operator is the SOLE primary user with occasional friends and family on the network — there are no customers. sessions_active counts distinct user_keys, not session rows. 0 is OK during quiet periods; >5 sustained warrants a look.
- bandwidth: 50-200 GB inbound and 5-30 GB outbound per 2h is normal during active use (streaming, downloads, syncs)
- events_total ~2,000-4,000 per cycle is steady-state public-IP scanner noise
- events_high ~400-700 per cycle is normal — almost all of it is honeypot hits + fail2ban actions (the honeypot's literal job is to get hit; fail2ban's job is to ban repeat offenders). NEITHER is anomalous on its own.
- events_medium ~1,000-1,500 (mostly ssh_failure, the SSH brute-force background)
- top_event_types steadily contains: ssh_failure, ufw_block, honeypot, fail2ban

Flag IMPORTANT = true ONLY if any of:
  1. anomalies_open > 0 (the system itself flagged something)
  2. events_critical > 0 (any critical event)
  3. A NEW event_type appears in top_event_types that is NOT in {ssh_failure, ufw_block, honeypot, fail2ban} (suggests a novel attack vector or a new detection rule firing)
  4. An internal WireGuard tunnel IP (10.8.0.0/24) appears in top_source_ips (would indicate a compromised peer or operator's own traffic tripping IDS rules — both worth a look)
  5. events_high > 1,500 (>3x baseline — sustained heavy attack, not routine)
  6. events_total > 25,000 (>5x baseline — burst attack)
  7. sessions_active == 0 for two cycles in a row (operator has lost connectivity)
  8. bandwidth pattern is structurally weird — e.g. bytes_out >> bytes_in (data exfiltration shape) or bytes_in suddenly 10x prior cycles

Do NOT flag IMPORTANT just because events_high > 0 or sessions are above 30. Those are baseline.

Respond ONLY with valid JSON, no other text:
{
  "summary": "<2-3 sentence operator-friendly summary; mention the dominant event_type, any notable source IPs, and whether this is a quiet or busy cycle relative to baseline>",
  "important": <true|false>,
  "reason": "<one short sentence — which rule above fired; empty string if not important>"
}`;

const body = {
  model: "claude-sonnet-4-6",
  max_tokens: 600,
  system: [
    {
      type: "text",
      text: systemPrompt,
      cache_control: { type: "ephemeral" }
    }
  ],
  messages: [
    {
      role: "user",
      content: "Analyze this 2-hour pulse and return the JSON verdict:\n\n" + JSON.stringify(payload, null, 2)
    }
  ],
  output_config: {
    format: {
      type: "json_schema",
      schema: {
        type: "object",
        properties: {
          summary:   { type: "string" },
          important: { type: "boolean" },
          reason:    { type: "string" }
        },
        required: ["summary", "important", "reason"],
        additionalProperties: false
      }
    }
  }
};

return [{ json: { body, payload } }];

// Extract Claude's JSON verdict from the response.
// Claude returns content as an array of blocks; we want the first text block.

const response = $json;
const textBlock = (response.content || []).find(b => b.type === 'text');
const rawText = textBlock ? textBlock.text : '';

let verdict;
try {
  // With output_config.format, the entire text block IS the JSON.
  // As a fallback for chatty models, strip anything outside the first { ... }
  // pair so a preamble or trailing prose doesn't break parsing.
  let cleaned = rawText.trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace  = cleaned.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace > firstBrace) {
    cleaned = cleaned.slice(firstBrace, lastBrace + 1);
  }
  verdict = JSON.parse(cleaned);
} catch (e) {
  verdict = {
    summary: 'Parse error: Claude response was not valid JSON. Raw text: ' + rawText.slice(0, 500),
    important: true,
    reason: 'Claude response failed to parse — investigate workflow'
  };
}

const usage = response.usage || {};
const payload = $('Build Claude Request').first().json.payload;

return [{
  json: {
    // Verdict from Claude
    summary:   verdict.summary || '',
    important: verdict.important === true,
    reason:    verdict.reason || '',
    // Source metrics for the INSERT
    period_start:    payload.period_start,
    period_end:      payload.period_end,
    sessions_active: payload.sessions_active,
    sessions_new:    payload.sessions_new,
    bytes_in:        payload.bytes_in,
    bytes_out:       payload.bytes_out,
    events_total:    payload.events_total,
    events_high:     payload.events_high,
    events_medium:   payload.events_medium,
    events_critical: payload.events_critical,
    anomalies_open:  payload.anomalies_open,
    top_source_ips:  payload.top_source_ips,
    top_event_types: payload.top_event_types,
    // Raw + token usage
    raw_payload:         payload,
    raw_claude_response: response,
    model_used:    response.model || 'claude-opus-4-7',
    input_tokens:  usage.input_tokens || 0,
    output_tokens: usage.output_tokens || 0,
    // For ntfy push
    ntfy_topic:  $('Set Period & Topic').first().json.ntfy_topic,
    ntfy_server: $('Set Period & Topic').first().json.ntfy_server
  }
}];
